SELECT

FROM recovery_judgement t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.flow_state = #{request.flowState}


    AND t0.filling_date BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.is_stock = #{request.isStock}


    AND t0.filing_court_name LIKE CONCAT ('%',#{request.filingCourtName},'%')


    AND t0.judge_name LIKE CONCAT ('%',#{request.judgeName},'%')


    AND t0.judge_phone LIKE CONCAT ('%',#{request.judgePhone},'%')


    AND t0.filling_date = #{request.fillingDate}


    AND t0.litigation_type = #{request.litigationType}


    AND t0.register_type = #{request.registerType}


    AND t0.litigation_type in

      #{ids}



    AND t0.register_id = #{request.registerId}


    AND t0.filling_code LIKE CONCAT ('%',#{request.fillingCode},'%')


    AND t0.judge_date = #{request.judgeDate}


    AND t0.court_session_date = #{request.courtSessionDate}


    AND t0.litigation_id = #{request.litigationId}


    AND t0.project_id = #{request.projectId}


    AND t0.law_firm_id = #{request.lawFirmId}


    AND t0.remarks = #{request.remarks}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
